 70â†’export function earliestTimestamp(current: string, candidate: unknown): string {
 71â†’  const normalized = normalizeTimestamp(candidate, current)
 72â†’  const currentDt = parseIsoTimestamp(current)
 73â†’  const normalizedDt = parseIsoTimestamp(normalized)
 74â†’  if (currentDt !== null && normalizedDt !== null) {
 75â†’    return normalizedDt < currentDt ? normalized : current
 76â†’  }
 77â†’  if (normalizedDt !== null) {
 78â†’    return normalized
 79â†’  }
 80â†’  return current || normalized
 81â†’}
