105â†’export function joinParagraphs(parts: Iterable<string>): string {
106â†’  const cleaned: string[] = []
107â†’  for (const part of parts) {
108â†’    const trimmed = String(part).trim()
109â†’    if (trimmed) cleaned.push(trimmed)
110â†’  }
111â†’  return cleaned.join('\n\n')
112â†’}
