114â†’export function summarizeValue(value: unknown, limit = 180): string {
115â†’  if (value === null || value === undefined) return 'none'
116â†’  if (typeof value === 'string') {
117â†’    const text = value.replace(/\s+/g, ' ').trim()
118â†’    return truncate(text, limit)
119â†’  }
120â†’  let text: string
121â†’  try {
122â†’    text = JSON.stringify(sortKeysDeep(value))
123â†’  } catch {
124â†’    text = String(value)
125â†’  }
126â†’  text = text.replace(/\s+/g, ' ').trim()
127â†’  return truncate(text, limit)
128â†’}
