154â†’export function getNested(payload: Record<string, unknown>, ...keys: string[]): unknown {
155â†’  let current: unknown = payload
156â†’  for (const key of keys) {
157â†’    if (current === null || typeof current !== 'object' || Array.isArray(current)) {
158â†’      return null
159â†’    }
160â†’    current = (current as Record<string, unknown>)[key]
161â†’  }
162â†’  return current ?? null
163â†’}
