165â†’export function loadJsonl(filePath: string): Record<string, unknown>[] {
166â†’  let content: string
167â†’  try {
168â†’    content = readFileSync(filePath, 'utf-8')
169â†’  } catch {
170â†’    return []
171â†’  }
172â†’  const records: Record<string, unknown>[] = []
173â†’  for (const line of content.split('\n')) {
174â†’    const trimmed = line.trim()
175â†’    if (!trimmed) continue
176â†’    try {
177â†’      records.push(JSON.parse(trimmed) as Record<string, unknown>)
178â†’    } catch {
179â†’      continue
180â†’    }
181â†’  }
182â†’  return records
183â†’}
