185â†’export function loadJson(filePath: string): Record<string, unknown> | null {
186â†’  if (!existsSync(filePath)) return null
187â†’  try {
188â†’    const text = readFileSync(filePath, 'utf-8')
189â†’    return JSON.parse(text) as Record<string, unknown>
190â†’  } catch {
191â†’    return null
192â†’  }
193â†’}
