199â†’export function extractTextBlocks(blocks: unknown): string {
200â†’  const parts: string[] = []
201â†’
202â†’  for (const block of ensureList(blocks)) {
203â†’    if (typeof block === 'string') {
204â†’      const text = block.trim()
205â†’      if (text) parts.push(text)
206â†’      continue
207â†’    }
208â†’    if (block === null || typeof block !== 'object' || Array.isArray(block)) continue
209â†’
210â†’    const rec = block as Record<string, unknown>
211â†’    const blockType = String(rec['type'] ?? '').toLowerCase()
212â†’    if (ALL_SKIP_TYPES.has(blockType)) continue
213â†’    if (TEXT_BLOCK_TYPES.has(blockType)) {
214â†’      const text = String(rec['text'] ?? '').trim()
215â†’      if (text) parts.push(text)
216â†’      continue
217â†’    }
218â†’    const fallbackText = extractSimpleText(block)
219â†’    if (fallbackText) parts.push(fallbackText)
220â†’  }
221â†’  return joinParagraphs(parts)
222â†’}
