224â†’export function extractSimpleText(value: unknown): string {
225â†’  if (typeof value === 'string') return value.trim()
226â†’  if (Array.isArray(value)) {
227â†’    return joinParagraphs(value.map(item => extractSimpleText(item)))
228â†’  }
229â†’  if (value !== null && typeof value === 'object') {
230â†’    const rec = value as Record<string, unknown>
231â†’    for (const key of ['text', 'content', 'value']) {
232â†’      if (key in rec && typeof rec[key] === 'string') {
233â†’        return (rec[key] as string).trim()
234â†’      }
235â†’    }
236â†’    return ''
237â†’  }
238â†’  return ''
239â†’}
