241â†’export function extractGeminiText(node: Record<string, unknown>): string {
242â†’  const parts: string[] = []
243â†’  for (const key of ['parts', 'content', 'text', 'message']) {
244â†’    parts.push(...extractGeminiParts(node[key]))
245â†’  }
246â†’  return joinParagraphs(parts)
