249â†’export function extractGeminiParts(value: unknown): string[] {
250â†’  if (typeof value === 'string') {
251â†’    const text = value.trim()
252â†’    return text ? [text] : []
253â†’  }
254â†’  if (Array.isArray(value)) {
255â†’    const parts: string[] = []
256â†’    for (const item of value) {
257â†’      parts.push(...extractGeminiParts(item))
258â†’    }
259â†’    return parts
260â†’  }
261â†’  if (value !== null && typeof value === 'object') {
262â†’    const rec = value as Record<string, unknown>
263â†’    const blockType = String(rec['type'] ?? '').toLowerCase()
264â†’    if (ALL_SKIP_TYPES.has(blockType)) return []
265â†’    if ('text' in rec && typeof rec['text'] === 'string') {
266â†’      const text = (rec['text'] as string).trim()
267â†’      return text ? [text] : []
268â†’    }
269â†’    const parts: string[] = []
270â†’    for (const key of ['parts', 'content']) {
271â†’      if (key in rec) {
272â†’        parts.push(...extractGeminiParts(rec[key]))
273â†’      }
274â†’    }
275â†’    return parts
276â†’  }
277â†’  return []
278â†’}
