280â†’export function findFirstMappingWithKeys(value: unknown, keys: ReadonlySet<string>): Record<string, unknown> | null {
281â†’  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
282â†’    const rec = value as Record<string, unknown>
283â†’    const recKeys = Object.keys(rec)
284â†’    if (recKeys.some(k => keys.has(k))) return rec
285â†’    for (const v of Object.values(rec)) {
286â†’      const result = findFirstMappingWithKeys(v, keys)
287â†’      if (result !== null) return result
288â†’    }
289â†’    return null
290â†’  }
291â†’  if (Array.isArray(value)) {
292â†’    for (const item of value) {
293â†’      const result = findFirstMappingWithKeys(item, keys)
294â†’      if (result !== null) return result
295â†’    }
296â†’  }
297â†’  return null
298â†’}
