304â†’export function deduplicateMessages(messages: readonly TranscriptMessage[]): TranscriptMessage[] {
305â†’  const seen = new Set<string>()
306â†’  const result: TranscriptMessage[] = []
307â†’  for (const msg of messages) {
308â†’    const sig = `${msg.timestamp ?? ''}\0${msg.role}\0${contentHash(msg.text)}`
309â†’    if (!seen.has(sig)) {
310â†’      seen.add(sig)
311â†’      result.push(msg)
312â†’    }
313â†’  }
314â†’  return result
315â†’}
