317â†’export function deduplicateToolEvents(events: readonly TranscriptToolEvent[]): TranscriptToolEvent[] {
318â†’  const seen = new Set<string>()
319â†’  const result: TranscriptToolEvent[] = []
320â†’  for (const evt of events) {
321â†’    const sig = `${evt.timestamp ?? ''}\0${contentHash(evt.summary)}`
322â†’    if (!seen.has(sig)) {
323â†’      seen.add(sig)
324â†’      result.push(evt)
325â†’    }
326â†’  }
327â†’  return result
328â†’}
