334â†’function sortKeysDeep(value: unknown): unknown {
335â†’  if (Array.isArray(value)) return value.map(sortKeysDeep)
336â†’  if (value !== null && typeof value === 'object') {
337â†’    const sorted: Record<string, unknown> = {}
338â†’    for (const key of Object.keys(value as Record<string, unknown>).sort()) {
339â†’      sorted[key] = sortKeysDeep((value as Record<string, unknown>)[key])
340â†’    }
341â†’    return sorted
342â†’  }
343â†’  return value
344â†’}
