346â†’function formatUtcIso(d: Date): string {
347â†’  const year = d.getUTCFullYear()
348â†’  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
349â†’  const day = String(d.getUTCDate()).padStart(2, '0')
350â†’  const hours = String(d.getUTCHours()).padStart(2, '0')
351â†’  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
352â†’  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
353â†’  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
354â†’}
